const { ethers } = require('ethers');

const ERC20_ABI = ['function balanceOf(address) view returns (uint256)', 'function decimals() view returns (uint8)', 'function symbol() view returns (string)'];

async function getBalance({ rpcUrl, tokenAddress, walletAddress }) {
  const provider = new ethers.JsonRpcProvider(rpcUrl);
  const token = new ethers.Contract(tokenAddress, ERC20_ABI, provider);
  const [balance, decimals, symbol] = await Promise.all([
    token.balanceOf(walletAddress),
    token.decimals(),
    token.symbol()
  ]);
  return {
    raw: balance.toString(),
    formatted: ethers.formatUnits(balance, decimals),
    symbol,
    decimals
  };
}

module.exports = { getBalance };

const { ethers } = require('ethers');

const ERC20_ABI = ['function transfer(address to, uint256 amount) returns (bool)', 'function decimals() view returns (uint8)'];

async function transfer({ rpcUrl, privateKey, tokenAddress, to, amount }) {
  const provider = new ethers.JsonRpcProvider(rpcUrl);
  const wallet = new ethers.Wallet(privateKey, provider);
  const token = new ethers.Contract(tokenAddress, ERC20_ABI, wallet);
  const decimals = await token.decimals();
  const tx = await token.transfer(to, ethers.parseUnits(amount, decimals));
  const receipt = await tx.wait();
  return { tx_hash: receipt.hash, status: receipt.status === 1 ? 'success' : 'failed' };
}

module.exports = { transfer };

